//! Generate webmcp.js — browser script that registers tools with navigator.modelContext.

use crate::manifest::WebMCPManifest;

/// Generate the webmcp.js registration script.
pub fn emit_js(manifest: &WebMCPManifest) -> String {
    format!(
        r#"/**
 * WebMCP tool registration for {name}
 * Auto-generated by ic-webmcp-codegen — do not edit manually.
 *
 * Usage:
 *   <script type="module" src="/webmcp.js"></script>
 *
 * Or import directly:
 *   import {{ initWebMCP }} from './webmcp.js';
 *   await initWebMCP();
 */

import {{ ICWebMCP }} from 'https://esm.sh/@dfinity/webmcp';

export async function initWebMCP(options = {{}}) {{
  const webmcp = new ICWebMCP({{
    manifestUrl: options.manifestUrl || '/.well-known/webmcp.json',
    canisterId: options.canisterId || {canister_id},
    host: options.host || 'https://icp-api.io',
    ...options,
  }});

  await webmcp.registerAll();

  return webmcp;
}}

// Auto-initialize if loaded as a script tag
if (document.currentScript) {{
  initWebMCP().catch(console.error);
}}
"#,
        name = manifest.canister.name,
        canister_id = manifest
            .canister
            .id
            .as_deref()
            .map(|id| format!("'{}'", id))
            .unwrap_or_else(|| "undefined".to_string()),
    )
}
